import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import api from '../services/api';

const Home = () => {
  const { user } = useAuth();
  const [popularGames, setPopularGames] = useState([]);
  const [nextEvents, setNextEvents] = useState([]);

  useEffect(() => {
    loadHomeData();
  }, []);

  const loadHomeData = async () => {
    try {
      const [gamesRes, eventsRes] = await Promise.all([
        api.get('/api/casino/games'),
        api.get('/api/sports/events')
      ]);
      setPopularGames(gamesRes.data.filter(g => g.category === 'PG Style').slice(0, 4));
      setNextEvents(eventsRes.data.filter(e => e.status !== 'live').slice(0, 3));
    } catch (err) {
      console.error('Erro ao carregar dados da home');
    }
  };

  const styles = {
    hero: {
      background: 'linear-gradient(rgba(0,0,0,0.7), rgba(0,0,0,0.7)), url("https://images.unsplash.com/photo-1596838132731-3301c3fd4317?ixlib=rb-1.2.1&auto=format&fit=crop&w=1350&q=80")',
      backgroundSize: 'cover', backgroundPosition: 'center', minHeight: '70vh',
      display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center',
      textAlign: 'center', padding: '40px 20px', position: 'relative', overflow: 'hidden'
    },
    section: { padding: '60px 20px', maxWidth: '1200px', margin: '0 auto' },
    sectionTitle: { fontFamily: "'Orbitron', sans-serif", fontSize: '24px', color: '#FFD700', marginBottom: '30px', textAlign: 'center' },
    gameGrid: { display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(250px, 1fr))', gap: '20px' },
    gameCard: { background: '#1a1a1a', borderRadius: '16px', padding: '20px', textAlign: 'center', border: '1px solid #2a2a2a', transition: '0.3s' },
    eventList: { display: 'flex', flexDirection: 'column', gap: '15px' },
    eventCard: { background: '#1a1a1a', borderRadius: '12px', padding: '20px', display: 'flex', justifyContent: 'space-between', alignItems: 'center', border: '1px solid #2a2a2a' },
    aiHighlight: { background: 'linear-gradient(135deg, #1a1a1a, #000)', border: '1px solid #FFD700', borderRadius: '20px', padding: '40px', textAlign: 'center', marginTop: '40px' }
  };

  return (
    <div>
      {/* HERO BANNER */}
      <div style={styles.hero}>
        <h1 style={{ fontFamily: "'Orbitron', sans-serif", fontSize: 'clamp(40px, 8vw, 80px)', fontWeight: 900, marginBottom: '20px' }}>
          <span style={{ color: '#ff1744' }}>W.M</span> <span style={{ color: '#FFD700' }}>ESPORTE013</span>
        </h1>
        <p style={{ fontSize: '20px', color: '#ccc', maxWidth: '800px', marginBottom: '40px' }}>
          A maior plataforma de apostas e cassino do Brasil. Análises de IA em tempo real e os melhores jogos da PG Soft.
        </p>
        <div style={{ display: 'flex', gap: '20px', flexWrap: 'wrap', justifyContent: 'center' }}>
          {!user ? (
            <Link to="/register"><button className="btn-gold" style={{ padding: '15px 40px', fontSize: '18px' }}>CRIAR CONTA AGORA</button></Link>
          ) : (
            <Link to="/casino"><button className="btn-gold" style={{ padding: '15px 40px', fontSize: '18px' }}>🎰 IR PARA O CASSINO</button></Link>
          )}
        </div>
      </div>

      {/* JOGOS POPULARES */}
      <div style={styles.section}>
        <h2 style={styles.sectionTitle}>🔥 JOGOS POPULARES DA PG SOFT</h2>
        <div style={styles.gameGrid}>
          {popularGames.map(game => (
            <Link to="/casino" key={game.id} style={{ textDecoration: 'none' }}>
              <div style={styles.gameCard} className="card-hover">
                <span style={{ fontSize: '60px', display: 'block', marginBottom: '15px' }}>{game.icon}</span>
                <h3 style={{ color: '#fff', fontSize: '18px', marginBottom: '10px' }}>{game.name}</h3>
                <p style={{ color: '#888', fontSize: '12px' }}>Multiplicadores de até {game.multiplier}x</p>
                <button style={{ marginTop: '15px', background: 'transparent', border: '1px solid #FFD700', color: '#FFD700', padding: '8px 20px', borderRadius: '20px', fontSize: '12px', fontWeight: 700 }}>JOGAR AGORA</button>
              </div>
            </Link>
          ))}
        </div>
      </div>

      {/* PRÓXIMOS JOGOS */}
      <div style={{ ...styles.section, background: '#0a0a0a' }}>
        <h2 style={styles.sectionTitle}>📅 PRÓXIMOS GRANDES EVENTOS</h2>
        <div style={styles.eventList}>
          {nextEvents.map(event => (
            <div key={event.id} style={styles.eventCard}>
              <div>
                <div style={{ color: '#FFD700', fontSize: '12px', fontWeight: 700 }}>{event.league}</div>
                <div style={{ color: '#fff', fontSize: '18px', fontWeight: 800, margin: '5px 0' }}>{event.team1} vs {event.team2}</div>
                <div style={{ color: '#666', fontSize: '12px' }}>{new Date(event.date).toLocaleString()}</div>
              </div>
              <div style={{ display: 'flex', gap: '10px' }}>
                <div style={{ textAlign: 'center', background: '#2a2a2a', padding: '10px', borderRadius: '8px', minWidth: '60px' }}>
                  <div style={{ fontSize: '10px', color: '#888' }}>CASA</div>
                  <div style={{ color: '#FFD700', fontWeight: 800 }}>{event.odds.team1Win.toFixed(2)}</div>
                </div>
                <Link to="/sports"><button className="btn-gold" style={{ height: '100%', padding: '0 20px' }}>APOSTAR</button></Link>
              </div>
            </div>
          ))}
        </div>
        <div style={{ textAlign: 'center', marginTop: '30px' }}>
          <Link to="/sports" style={{ color: '#FFD700', textDecoration: 'none', fontWeight: 700 }}>VER TODOS OS EVENTOS ➔</Link>
        </div>
      </div>

      {/* DESTAQUE IA */}
      <div style={styles.section}>
        <div style={styles.aiHighlight}>
          <h2 style={{ fontFamily: "'Orbitron', sans-serif", fontSize: '32px', color: '#FFD700', marginBottom: '20px' }}>🤖 W.M IA ANALYTICS</h2>
          <p style={{ color: '#ccc', fontSize: '18px', maxWidth: '700px', margin: '0 auto 30px' }}>
            Nossa inteligência artificial analisa milhares de dados em tempo real para te dar as melhores dicas de apostas. Aumente suas chances em até 85%!
          </p>
          <Link to="/ai"><button className="btn-gold" style={{ padding: '15px 50px', fontSize: '18px' }}>VER ANÁLISES AO VIVO</button></Link>
        </div>
      </div>

      {/* FOOTER */}
      <footer style={{ padding: '60px 20px', borderTop: '1px solid #2a2a2a', textAlign: 'center', color: '#666' }}>
        <h3 style={{ color: '#FFD700', fontFamily: "'Orbitron', sans-serif", marginBottom: '20px' }}>W.M ESPORTE013</h3>
        <p>© 2026 W.M esporte013. A maior casa de apostas do Brasil.</p>
        <p style={{ marginTop: '10px', fontSize: '12px' }}>O jogo é proibido para menores de 18 anos. Jogue com responsabilidade.</p>
      </footer>

      <style>{`
        .card-hover:hover { transform: translateY(-10px); border-color: #FFD700; box-shadow: 0 10px 30px rgba(255,215,0,0.1); }
      `}</style>
    </div>
  );
};

export default Home;
